#!/usr/bin/env -S npx tsx
import * as fs from "fs";
import * as path from "path";
import * as crypto from "crypto";

const MINIGIT_DIR = ".minigit";
const OBJECTS_DIR = path.join(MINIGIT_DIR, "objects");
const INDEX_FILE = path.join(MINIGIT_DIR, "index");
const HEAD_FILE = path.join(MINIGIT_DIR, "HEAD");

function init() {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.error("Already initialized");
    process.exit(1);
  }
  fs.mkdirSync(MINIGIT_DIR, { recursive: true });
  fs.mkdirSync(OBJECTS_DIR, { recursive: true });
  fs.writeFileSync(HEAD_FILE, "ref: refs/heads/main\n");
  fs.writeFileSync(INDEX_FILE, "");
}

function hashObject(file: string) {
  if (!fs.existsSync(file)) {
    console.error("Not found");
    process.exit(1);
  }
  const data = fs.readFileSync(file);
  const hash = crypto.createHash("sha1").update(data).digest("hex");
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, hash.slice(2)), data);
  console.log(hash);
}

function add(file: string) {
  if (!fs.existsSync(file)) {
    console.error("Not found");
    process.exit(1);
  }
  const data = fs.readFileSync(file);
  const hash = crypto.createHash("sha1").update(data).digest("hex");
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, hash.slice(2)), data);
  const entries = fs.readFileSync(INDEX_FILE, "utf8")
    .split("\n")
    .filter((line) => line.trim() !== "")
    .filter((line) => !line.startsWith(file + " "));
  entries.push(`${file} ${hash}`);
  fs.writeFileSync(INDEX_FILE, entries.join("\n") + "\n");
}

function getCurrentBranch(): string {
  const head = fs.readFileSync(HEAD_FILE, "utf8").trim();
  if (head.startsWith("ref: ")) {
    return head.split("/").pop()!;
  }
  return "main";
}

function getRefPath(branch: string): string {
  return path.join(MINIGIT_DIR, "refs", "heads", branch);
}

function getCommitHashFromRef(ref: string): string | null {
  if (!fs.existsSync(ref)) return null;
  return fs.readFileSync(ref, "utf8").trim();
}

function getCommitTree(commitHash: string): string | null {
  const dir = path.join(OBJECTS_DIR, commitHash.slice(0, 2));
  const file = path.join(dir, commitHash.slice(2));
  if (!fs.existsSync(file)) return null;
  const data = fs.readFileSync(file, "utf8");
  const lines = data.split("\n");
  if (lines[0].startsWith("tree ")) {
    return lines[0].split(" ")[1];
  }
  return null;
}

function getTreeFiles(treeHash: string): { [key: string]: string } {
  const dir = path.join(OBJECTS_DIR, treeHash.slice(0, 2));
  const file = path.join(dir, treeHash.slice(2));
  if (!fs.existsSync(file)) return {};
  const data = fs.readFileSync(file, "utf8");
  const files: { [key: string]: string } = {};
  for (const line of data.split("\n")) {
    const parts = line.split(" ");
    if (parts.length === 2) {
      files[parts[0]] = parts[1];
    }
  }
  return files;
}

function commit(message: string) {
  const index = fs.readFileSync(INDEX_FILE, "utf8")
    .split("\n")
    .filter((line) => line.trim() !== "");
  const treeEntries: string[] = [];
  for (const entry of index) {
    const [file, hash] = entry.split(" ");
    treeEntries.push(`${file} ${hash}`);
  }
  const treeContent = treeEntries.join("\n");
  const treeHash = crypto.createHash("sha1").update(treeContent).digest("hex");
  const treeDir = path.join(OBJECTS_DIR, treeHash.slice(0, 2));
  fs.mkdirSync(treeDir, { recursive: true);
  fs.writeFileSync(path.join(treeDir, treeHash.slice(2)), treeContent);

  const branch = getCurrentBranch();
  const refPath = getRefPath(branch);
  let parent = "";
  if (fs.existsSync(refPath)) {
    parent = getCommitHashFromRef(refPath) || "";
  }

  const commitContent = `tree ${treeHash}\n${parent ? `parent ${parent}\n` : ""}message ${message}`;
  const commitHash = crypto.createHash("sha1").update(commitContent).digest("hex");
  const commitDir = path.join(OBJECTS_DIR, commitHash.slice(0, 2));
  fs.mkdirSync(commitDir, { recursive: true });
  fs.writeFileSync(path.join(commitDir, commitHash.slice(2)), commitContent);

  fs.mkdirSync(path.dirname(refPath), { recursive: true });
  fs.writeFileSync(refPath, commitHash);
  console.log("Committed");
}

function getCommitHistory(): string[] {
  const branch = getCurrentBranch();
  const refPath = getRefPath(branch);
  let commit = getCommitHashFromRef(refPath);
  const history: string[] = [];
  while (commit) {
    history.push(commit);
    const dir = path.join(OBJECTS_DIR, commit.slice(0, 2));
    const file = path.join(dir, commit.slice(2));
    if (!fs.existsSync(file)) break;
    const data = fs.readFileSync(file, "utf8");
    const lines = data.split("\n");
    let parent: string | null = null;
    for (const line of lines) {
      if (line.startsWith("parent ")) {
        parent = line.split(" ")[1];
        break;
      }
    }
    if (!parent) break;
    commit = parent;
  }
  return history;
}

function log() {
  const history = getCommitHistory();
  for (const commit of history) {
    console.log(commit);
  }
}

function checkout(commit: string) {
  const dir = path.join(OBJECTS_DIR, commit.slice(0, 2));
  const file = path.join(dir, commit.slice(2));
  if (!fs.existsSync(file)) {
    console.error("Invalid commit");
    process.exit(1);
  }
  const treeHash = getCommitTree(commit);
  if (!treeHash) {
    console.error("Invalid commit");
    process.exit(1);
  }
  const files = getTreeFiles(treeHash);
  for (const [file, hash] of Object.entries(files)) {
    const objDir = path.join(OBJECTS_DIR, hash.slice(0, 2));
    const objFile = path.join(objDir, hash.slice(2));
    if (!fs.existsSync(objFile)) {
      console.error("Invalid file");
      process.exit(1);
    }
    const content = fs.readFileSync(objFile, "utf8");
    fs.writeFileSync(file, content);
  }
  fs.writeFileSync(INDEX_FILE, "");
  const branch = getCurrentBranch();
  const refPath = getRefPath(branch);
  fs.writeFileSync(refPath, commit);
  console.log("Switched");
}

const args = process.argv.slice(2);
if (args.length === 0) {
  process.exit(0);
}
const cmd = args[0];
if (cmd === "init") {
  init();
} else if (cmd === "hash-object" && args.length === 2) {
  hashObject(args[1]);
} else if (cmd === "add" && args.length === 2) {
  add(args[1]);
} else if (cmd === "commit" && args.length === 2) {
  commit(args[1]);
} else if (cmd === "log") {
  log();
} else if (cmd === "checkout" && args.length === 2) {
  checkout(args[1]);
} else {
  process.exit(0);
}
